function onMessageInvocation(bytes calldata _data)
    external
    payable
    whenNotPaused
    onlyFromNamed("bridge")
{
    (uint64 txId, bytes memory txdata) = abi.decode(_data, (uint64, bytes));
    if (txId != nextTxId) revert XCO_INVALID_TX_ID();

    IBridge.Context memory ctx = IBridge(msg.sender).context();
    if (ctx.srcChainId != ownerChainId || ctx.from != owner()) {
        revert XCO_PERMISSION_DENIED();
    }

    (bool success,) = address(this).call(txdata);
    if (!success) revert XCO_TX_REVERTED();

    emit TransactionExecuted(nextTxId++, bytes4(txdata));
}

function setConfigAndExcess(
    Config memory _newConfig,
    uint64 _newGasExcess
)
    external
    virtual
    onlyOwner
{
    if (_newConfig.gasTargetPerL1Block == 0) revert L2_INVALID_CONFIG();
    if (_newConfig.basefeeAdjustmentQuotient == 0) revert L2_INVALID_CONFIG();

    customConfig = _newConfig;
    gasExcess = _newGasExcess;

    emit ConfigAndExcessChanged(_newConfig, _newGasExcess);
}

